      hv_Sublabels.Dispose();
      hv_Ascent.Dispose();
      hv_Descent.Dispose();
      hv_TextWidth.Dispose();
      hv_TextHeight.Dispose();
      hv_Index2.Dispose();
      hv_TextWidth2.Dispose();
      hv_TextHeight2.Dispose();
      hv_RotCenterRow.Dispose();
