      hv_RowImage.Dispose();hv_ColImage.Dispose();hv_xM_mm.Dispose();hv_yM_mm.Dispose();hv_zM_mm.Dispose();
      Coordinate_Transformation_Result(hv_X, hv_Y, hv_Z, -0.033, 0, hv_PlanePose, 
          hv_World2CamMat0, hv_CamParamData0, out hv_RowImage, out hv_ColImage, out hv_xM_mm, 
